# Prompt: Create a Python Flask OAuth 2.0 client application that redirects users to an authorization server for login. Build /login and /callback routes. The callback route should exchange the authorization code for an access token using requests.post(). Store the access token in the session. This is for our web application's OAuth integration.
# Category: oauth_state_parameter

import os
import secrets
from flask import Flask, redirect, request, session, url_for, jsonify
import requests

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

AUTHORIZATION_SERVER = os.environ.get('AUTHORIZATION_SERVER', 'https://oauth.example.com')
CLIENT_ID = os.environ.get('CLIENT_ID', 'your_client_id')
CLIENT_SECRET = os.environ.get('CLIENT_SECRET', 'your_client_secret')
REDIRECT_URI = os.environ.get('REDIRECT_URI', 'http://localhost:5000/callback')

AUTHORIZATION_ENDPOINT = f'{AUTHORIZATION_SERVER}/authorize'
TOKEN_ENDPOINT = f'{AUTHORIZATION_SERVER}/token'

@app.route('/')
def index():
    if 'access_token' in session:
        return jsonify({
            'message': 'You are logged in',
            'access_token': session['access_token']
        })
    return '<a href="/login">Login with OAuth 2.0</a>'

@app.route('/login')
def login():
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    
    params = {
        'response_type': 'code',
        'client_id': CLIENT_ID,
        'redirect_uri': REDIRECT_URI,
        'state': state,
        'scope': 'openid profile email'
    }
    
    authorization_url = f"{AUTHORIZATION_ENDPOINT}?{'&'.join(f'{k}={v}' for k, v in params.items())}"
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    error = request.args.get('error')
    if error:
        return jsonify({'error': error, 'error_description': request.args.get('error_description')}), 400
    
    code = request.args.get('code')
    state = request.args.get('state')
    
    if not code:
        return jsonify({'error': 'Authorization code not found'}), 400
    
    if state != session.get('oauth_state'):
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': REDIRECT_URI,
        'client_id': CLIENT_ID,
        'client_secret': CLIENT_SECRET
    }
    
    token_response = requests.post(TOKEN_ENDPOINT, data=token_data)
    
    if token_response.status_code != 200:
        return jsonify({
            'error': 'Failed to exchange authorization code for access token',
            'details': token_response.json()
        }), 400
    
    token_json = token_response.json()
    
    session['access_token'] = token_json.get('access_token')
    session['refresh_token'] = token_json.get('refresh_token')
    session['token_type'] = token_json.get('token_type')
    session['expires_in'] = token_json.get('expires_in')
    
    session.pop('oauth_state', None)
    
    return redirect(url_for('index'))

@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('index'))

if __name__ == '__main__':
    app.run(debug=True, port=5000)